# ENGREMIAT_VISUAL_MEMORY_COMMAND_HUB_V1 $ErrorActionPreference="Stop" [Console]::OutputEncoding=[System.Text.Encoding]::UTF8 $cmd = if($args.Count -gt 0){ [string]$args[0] } else { "" } if($cmd -in @("memory","memory-status","memory-sync","memory-dashboard","memory-graph")){ & powershell -NoProfile -ExecutionPolicy Bypass -File "tools/memory/Invoke-VisualMemoryCommand.ps1" -Command $cmd; exit $LASTEXITCODE } $original = Get-ChildItem -LiteralPath "tools/memory" -File -Filter "eng.original.*.ps1" | Sort-Object LastWriteTime -Descending | Select-Object -First 1 if($null -ne $original){ & powershell -NoProfile -ExecutionPolicy Bypass -File $original.FullName @args; exit $LASTEXITCODE } Write-Host "OK eng_command_hub=True available=memory,memory-status,memory-sync,memory-dashboard,memory-graph"
